pragma solidity ^0.8.20;

interface IFlashBorrower { function onFlashLoan(uint256 amount) external payable; }

contract FlashLender {
    uint256 public fee;
    error InsufficientRepayment();

    constructor(uint256 _fee) payable { fee = _fee; }

    function flashLoan(address borrower, uint256 amount) external {
        uint256 before = [[SLOT self_bal]];
        (bool ok, ) = borrower.call{value: amount}("");
        require(ok, "send fail");
        uint256 owed = [[SLOT owed_calc]];
        IFlashBorrower(borrower).onFlashLoan(amount);
        if ([[SLOT repay_check]]) revert InsufficientRepayment();
    }

    receive() external payable {}
}

interface IFlashLender { function flashLoan(address, uint256) external; function fee() external view returns (uint256); }

contract FlashBorrower {
    address public lender;
    uint256 public profitAccumulated;
    error Unauthorized();

    constructor(address _lender) payable { lender = _lender; }

    function executeTrade() external {
        IFlashLender(lender).flashLoan(address(this), 10 ether);
    }

    function onFlashLoan(uint256 amount) external payable {
        if (msg.sender != lender) revert Unauthorized();
        uint256 feeBps = IFlashLender(lender).fee();
        uint256 owed = (amount * feeBps) / 10000;
        profitAccumulated += 1;
        (bool ok, ) = [[SLOT repay_call]];
        require(ok, "repay fail");
    }

    receive() external payable {}
}
